class Solution(object):
    def numberOfLines(self, widths, s):
        lines = 1
        current_width = 0
        for char in s:
            width = widths[ord(char) - ord('a')]
            if current_width + width <= 100:
                current_width += width
            else:
                lines += 1
                current_width = width
        return [lines, current_width]
